INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'plano'), 'SF-6', 'sf-6', 'Single Family Residence-6', 'This district is for single-family detached residential development with a minimum lot size of 6,000 square feet.', NULL, NULL, 6000, 60, NULL, NULL, NULL, NULL) ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'sf-6' AND z.city_id = (SELECT id FROM cities WHERE slug = 'plano') AND pu.name IN ('Accessory Building or Use', 'Caretaker''s/Guard''s Residence', 'Construction Yard (Temporary)', 'Field Office', 'Home-Based Business (No-Impact)', 'Home Occupation', 'Backyard Cottage', 'Electrical Substation', 'Private Utility (other than listed)', 'Service Yard (Public or Utility)', 'Sewage Treatment Plant', 'Transportation and Utility Structures/Facility', 'Utility Distribution/Transmission Line', 'Water Treatment Plant') ON CONFLICT DO NOTHING;
