INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'plano'), 'LI-1', 'li-1', 'Light Industrial-1', 'The LI Light Industrial District is designed to accommodate light manufacturing, assembly, research and wholesale activities with limitations on outdoor storage. Uses are generally within a completely enclosed building or structure.', 20, NULL, 20000, 85, 30, NULL, NULL, 'Loading spaces shall be provided as per Sec. 16.1400 for retail, commercial, and industrial uses.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
