INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'plano'), 'NBD', 'nbd', 'Neighborhood Business Design District', 'The NBD district is intended to create a zoning district that caters to a pleasant and active pedestrian-oriented environment defined by traditional neighborhood-friendly commercial and residential uses, low-rise building heights and masses, walkable streets defined by storefronts and building faces, and required open space.', 50, NULL, 435600, NULL, NULL, NULL, NULL, 'On-street parking along major and minor streets provides an additional buffer for pedestrians. Parking garages must be set back a minimum of 150 feet from existing residential zoning districts or residential uses outside of the NBD district.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'nbd' AND z.city_id = (SELECT id FROM cities WHERE slug = 'plano') AND pu.name IN ('Retail (small grocers, farmers markets, boutiques)', 'Entertainment (neighborhood theaters, dance studios)', 'Professional and Medical Offices', 'Services (salons, banks, gyms)', 'Residential uses (developed according to RCD standards)') ON CONFLICT DO NOTHING;
